import jwt
import datetime

SECRET_KEY = 'your-strong-secret-key'  # Use a secure configuration for this key
ISSUER = 'your-application-name'
AUDIENCE = 'your-audience'

def generate_jwt(user_id, role):
    payload = {
        'user_id': user_id,
        'role': role,
        'exp': datetime.datetime.utcnow() + datetime.timedelta(hours=1),
        'iss': ISSUER,
        'aud': AUDIENCE
    }
    token = jwt.encode(payload, SECRET_KEY, algorithm='HS256')
    return token

def verify_jwt(token):
    try:
        decoded = jwt.decode(token, SECRET_KEY, algorithms=["HS256"], options={"require": ["exp", "iss", "aud"]}, issuer=ISSUER, audience=AUDIENCE)
        return decoded
    except jwt.ExpiredSignatureError:
        return 'Token has expired'
    except jwt.InvalidTokenError:
        return 'Invalid token'

